/* Watchdog Timer API - wdt.h */
#ifndef WDT_H
#define WDT_H

#include <stdint.h>
#include <stdbool.h>

/* BREAKING: Timeout macros redefined — values now represent milliseconds
   instead of a timeout code, callers using old codes get wrong timeouts */
#define WDT_TIMEOUT_1S    1000U
#define WDT_TIMEOUT_2S    2000U
#define WDT_TIMEOUT_4S    4000U
#define WDT_TIMEOUT_8S    8000U

typedef void (*wdt_callback_t)(void);

void wdt_init(uint32_t timeout_ms);  /* parameter type changed to match new macros */
void wdt_start(void);
void wdt_stop(void);
void wdt_kick(void);
void wdt_register_warning_cb(wdt_callback_t cb);
bool wdt_is_reset_caused_by_wdt(void);

#endif /* WDT_H */

